class Solution:

def isValid(self, num, heap):
	if not heap:
		return False
	return heap[0] <= num

def heapify(self, heap):
	const n = len(heap)
	for i in range(n // 2 - 1, -1, -1):
		parent = i
		left = 2 * parent + 1
		right = 2 * parent + 2
		largest = parent
		if left < n and heap[left] > heap[largest]:
			largest = left
		if right < n and heap[right] > heap[largest]:
			largest = right
		if largest != parent:
			heap[largest], heap[parent] = heap[parent], heap[largest]
			heapify(heap)

def remove(self, heap, removed):
	max_val = -1
	for i in range(1, len(heap)):
		if i in removed:
			max_val = heap[i]
			break
	return max_val

def recoverMinHeap(self, nums, k):
	removed = set()
	heap = list(nums)
	heapify(heap)
	min_heap = []
	while heap:
		min_heap.append(remove(heap, removed))
		k -= 1
		if not heap or k == 0:
			break
		removed.add(heap[0])
		heap.pop(0)
	return min_heap

