class Solution {
isValid(num, heap) {
	if (!heap.length) return false;
	return heap[0] <= num;
}
heapify(heap) {
	const n = heap.length;
	for (let i = Math.floor(n / 2) - 1; i >= 0; --i) {
		const parent = i;
		const left = 2 * parent + 1;
		const right = 2 * parent + 2;
		let largest = parent;
		if (left < n && heap[left] > heap[largest])
			largest = left;
		if (right < n && heap[right] > heap[largest])
			largest = right;
		if (largest != parent) {
			const temp = heap[parent];
			heap[parent] = heap[largest];
			heap[largest] = temp;
			this.heapify(heap);
		}
	}
}
remove(heap, removed) {
	let max = -1;
	for (let i = 1; i < heap.length; ++i) {
		if (removed.has(heap[i])) {
			max = heap[i];
			break;
		}
	}
	return max;
}recoverMinHeap(nums, k) {
	const removed = new Set();
	const heap = [
		...nums
	];
	this.heapify(heap);
	const minHeap = [];
	while (heap.length && k > 0) {
		minHeap.push(this.remove(heap, removed));
		k -= 1;
	}
	return minHeap;
}

